/**
 * Release Notebook Trigger — Detects git push to main and triggers release-notebook skill
 *
 * Hook: PostToolUse (Bash) — async, fire-and-forget
 *
 * Activates when:
 * 1. The Bash command contains "git push" targeting "main" or "master"
 * 2. The current version differs from the last recorded version
 *
 * On trigger: writes a marker file that the next SessionStart can detect,
 * or outputs additionalContext suggesting the user run the release-notebook skill.
 *
 * This is a lightweight nudge — the actual notebook creation is done by
 * the release-notebook skill which requires MCP tools.
 */

import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult } from '../types.js';
import { logHook, outputSilentSuccess } from '../lib/common.js';
import { getHomeDir, joinPath } from '../lib/paths.js';
import { atomicWriteSync } from '../lib/atomic-write.js';

const HOOK_NAME = 'release-notebook-trigger';

/** Check if the Bash command is a git push to main/master */
function isMainPush(command: string): boolean {
  if (!command) return false;
  const normalized = command.toLowerCase().trim();
  // Match: git push [options] origin main, git push origin master, etc.
  return /git\s+push\b/.test(normalized) &&
    /\b(main|master)\b/.test(normalized);
}

/** Read current version from package.json */
function getCurrentVersion(): string | undefined {
  try {
    const pkgPath = join(process.cwd(), 'package.json');
    if (!existsSync(pkgPath)) return undefined;
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    return pkg.version;
  } catch {
    return undefined;
  }
}

/** Get the last version we triggered a notebook for */
function getLastTriggeredVersion(): string | undefined {
  try {
    const markerPath = joinPath(getHomeDir(), '.claude', 'analytics', 'release-notebook-last.txt');
    if (!existsSync(markerPath)) return undefined;
    return readFileSync(markerPath, 'utf8').trim();
  } catch {
    return undefined;
  }
}

/** Record that we triggered for this version */
function recordTrigger(version: string): void {
  try {
    const markerPath = joinPath(getHomeDir(), '.claude', 'analytics', 'release-notebook-last.txt');
    atomicWriteSync(markerPath, version);
  } catch {
    // Best-effort
  }
}

export default async function handler(input: HookInput): Promise<HookResult> {
  try {
    // Only care about Bash tool
    if (input.tool_name !== 'Bash') {
      return outputSilentSuccess();
    }

    const command = input.tool_input?.command || '';

    // Check if this is a git push to main
    if (!isMainPush(command)) {
      return outputSilentSuccess();
    }

    // Check if the push succeeded (tool_output should not indicate error)
    const rawOutput = input.tool_output as Record<string, unknown> | undefined;
    const output = String(rawOutput?.stdout ?? rawOutput?.output ?? '');
    if (output.includes('rejected') || output.includes('error:') || output.includes('failed')) {
      return outputSilentSuccess();
    }

    // Check version
    const currentVersion = getCurrentVersion();
    if (!currentVersion) {
      return outputSilentSuccess();
    }

    const lastVersion = getLastTriggeredVersion();
    if (lastVersion === currentVersion) {
      // Already triggered for this version
      return outputSilentSuccess();
    }

    // New version pushed to main — nudge the user
    logHook(HOOK_NAME, `Release push detected: v${currentVersion} to main`);
    recordTrigger(currentVersion);

    return {
      continue: true,
      hookSpecificOutput: {
        additionalContext: `[Release Notebook Reminder] You just pushed v${currentVersion} to main. Consider creating a release notebook: invoke the release-notebook skill to generate a versioned NotebookLM KB with changelog and docs.`,
      },
    };
  } catch (err) {
    logHook(HOOK_NAME, `Error: ${err}`);
    return outputSilentSuccess();
  }
}
